-- Delete the B matches
DELETE FROM[ecms].[tmp_patient_stg2]
WHERE  [mark]=1;

GO
-- Due to new match changes (3 levels), determination of partial A's and partial B's is deferred to beginning of stage0800_step1  NEB 2011-04-16


TRUNCATE TABLE [ecms].[tmp_patient_fz_input];
GO
TRUNCATE TABLE [ecms].[tmp_patient_fz_output];
GO

DROP TABLE IF EXISTS [ecms].tmp_patient_name_part_1;
GO

DROP TABLE IF EXISTS [ecms].tmp_patient_name_part_2;
GO 

DELETE FROM [ecms].[tmp_patient_stg3] 
WHERE name_first_middle_clean IN ('GIRL','BOY','BABY','TWIN','NEWBORN','SB','STILLBORN','SINGH','KAUR') 
/*AM: 2020-08-23: name_first_middle_clean is actually name part here, so do need to check for all the above names*/
/* AM:2020-08-25 added a condition to remove one letter matches */
OR LEN(name_first_middle_clean)=1
;/* -- or name_last_clean IN ('BABY', 'BOY', 'GIRL', 'TWIN');-- -- dont really need to check for this AM 2011-06-12 */
GO

DROP INDEX IF EXISTS [idx_master_row_id] ON [ecms].[tmp_patient_stg3];
GO
DROP INDEX IF EXISTS [idx_row_id] ON [ecms].[tmp_patient_stg3];
GO
CREATE CLUSTERED INDEX [idx_row_id] ON [ecms].[tmp_patient_stg3]
([row_id] );
GO
CREATE NONCLUSTERED INDEX [idx_master_row_id] ON [ecms].[tmp_patient_stg3]
([master_row_id]);
GO

-- Since fuzzy lookup will build an index table from its reference table, and issue table locks on that ref table, we are going to load the required reference data into a separate table before commencing fuzzy lookup:
TRUNCATE TABLE [ecms].[tmp_patient_master_stg2];
go
TRUNCATE TABLE [ecms].[tmp_patient_fz_input];
go
-- Empty output table for fuzzy matching:
TRUNCATE TABLE [ecms].[tmp_patient_fz_output];
go

DECLARE
  @start_y INT,
  @end_y   INT,
  @str_sql VARCHAR(2000)

SELECT
  @start_y=@0
  ,@end_y=@1

/*if @start_y = 0 set @start_y = 1970
if @end_y  = 0 set @end_y  = 2000*/
SET @str_sql ='alter view [ecms].[vw_patient_master_stg2_fz_set] as
select row_id,  name_first_middle_clean, name_last_clean, birth_date, gender,master_row_id, master_phn,
CAST(isnull (name_first_middle_clean + '' '', '''')+ isnull (name_last_clean, '''') AS VARCHAR (50)) as name_full_clean
from (
select row_id,isnull(name_first_middle_clean,'''') AS  name_first_middle_clean,isnull(name_last_clean,'''') AS name_last_clean, birth_date, gender,master_row_id, master_phn,
row_number() OVER (PARTITION BY isnull(name_first_middle_clean,''''), isnull(name_last_clean,''''), birth_date, gender,master_row_id, master_phn ORDER BY row_id) rn
from [ecms].[tmp_patient_master_stg2]
where  datepart(YEAR,birth_date) >= '+CAST(@start_y AS VARCHAR)+' and datepart(YEAR,birth_date) <= '+CAST(@end_y AS VARCHAR)+
' AND (isnull(name_first_middle_clean,'''')<>'''' AND isnull(name_last_clean,'''')<>'''')) ms where ms.rn=1 '

EXECUTE(@str_sql )
